import{_ as t,c as o,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Confidentialité: Protection des données | opencode-supermemory","description":"Comprenez le mécanisme de protection de la confidentialité d'opencode-supermemory. Apprenez à utiliser la balise private et configurer la clé API en toute sécurité.","frontmatter":{"title":"Confidentialité: Protection des données | opencode-supermemory","sidebarTitle":"Confidentialité","subtitle":"Confidentialité et sécurité des données : Comment protéger vos informations sensibles","description":"Comprenez le mécanisme de protection de la confidentialité d'opencode-supermemory. Apprenez à utiliser la balise private et configurer la clé API en toute sécurité.","tags":["Confidentialité","Sécurité","Configuration"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"fr/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"fr/supermemoryai/opencode-supermemory/security/privacy/index.md"}`),s={name:"fr/supermemoryai/opencode-supermemory/security/privacy/index.md"};function a(n,e,l,c,d,u){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="confidentialite-et-securite-des-donnees-comment-proteger-vos-informations-sensibles" tabindex="-1">Confidentialité et sécurité des données : Comment protéger vos informations sensibles <a class="header-anchor" href="#confidentialite-et-securite-des-donnees-comment-proteger-vos-informations-sensibles" aria-label="Permalink to &quot;Confidentialité et sécurité des données : Comment protéger vos informations sensibles&quot;">​</a></h1><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li><strong>Comprendre où vont les données</strong> : Savoir clairement quelles données seront téléchargées vers le cloud et lesquelles resteront localement.</li><li><strong>Maîtriser les techniques de masquage</strong> : Apprendre à utiliser la balise <code>&lt;private&gt;</code> pour empêcher le téléchargement d&#39;informations sensibles (comme les mots de passe, les clés).</li><li><strong>Gérer les clés en toute sécurité</strong> : Apprendre à configurer <code>SUPERMEMORY_API_KEY</code> de la manière la plus sécurisée.</li></ul><h2 id="idee-principale" tabindex="-1">Idée principale <a class="header-anchor" href="#idee-principale" aria-label="Permalink to &quot;Idée principale&quot;">​</a></h2><p>Lors de l&#39;utilisation d&#39;opencode-supermemory, comprendre le flux des données est crucial :</p><ol><li><strong>Stockage cloud</strong> : Vos mémoires sont stockées dans la base de données cloud Supermemory, pas dans des fichiers locaux. Cela signifie que vous avez besoin d&#39;une connexion réseau pour accéder aux mémoires.</li><li><strong>Masquage local</strong> : Pour protéger la confidentialité, le plugin effectue un masquage des données localement <strong>avant</strong> d&#39;envoyer les données vers le cloud.</li><li><strong>Contrôle explicite</strong> : Le plugin ne numérise pas automatiquement tous les fichiers pour les télécharger. Seul le contenu pertinent est traité lorsque l&#39;Agent appelle explicitement l&#39;outil <code>add</code> ou déclenche la compression.</li></ol><h3 id="mecanisme-de-masquage" tabindex="-1">Mécanisme de masquage <a class="header-anchor" href="#mecanisme-de-masquage" aria-label="Permalink to &quot;Mécanisme de masquage&quot;">​</a></h3><p>Le plugin intègre un filtre simple qui identifie spécifiquement la balise <code>&lt;private&gt;</code>.</p><ul><li><strong>Entrée</strong> : <code>Le mot de passe de la base de données ici est &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>Traitement</strong> : Le plugin détecte la balise et remplace son contenu par <code>[REDACTED]</code>.</li><li><strong>Téléchargement</strong> : <code>Le mot de passe de la base de données ici est [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">Conseil</p><p>Ce processus de traitement se produit dans le code interne du plugin, avant que les données ne quittent votre ordinateur.</p></div><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-configurer-la-cle-api-en-toute-securite" tabindex="-1">Étape 1 : Configurer la clé API en toute sécurité <a class="header-anchor" href="#etape-1-configurer-la-cle-api-en-toute-securite" aria-label="Permalink to &quot;Étape 1 : Configurer la clé API en toute sécurité&quot;">​</a></h3><p>Bien que vous puissiez écrire directement la clé API dans le fichier de configuration, pour éviter les fuites accidentelles (comme partager accidentellement le fichier de configuration avec quelqu&#39;un), nous recommandons de comprendre la logique de priorité.</p><p><strong>Règle de priorité</strong> :</p><ol><li><strong>Fichier de configuration</strong> (<code>~/.config/opencode/supermemory.jsonc</code>) : Priorité la plus élevée.</li><li><strong>Variable d&#39;environnement</strong> (<code>SUPERMEMORY_API_KEY</code>) : Utilisée si elle n&#39;est pas définie dans le fichier de configuration.</li></ol><p><strong>Pratique recommandée</strong> : Si vous souhaitez basculer flexiblement ou l&#39;utiliser dans un environnement CI/CD, utilisez les variables d&#39;environnement. Si vous êtes un développeur individuel, la configuration dans un fichier JSONC dans le répertoire utilisateur est également sûre (car il n&#39;est pas dans votre dépôt Git du projet).</p><h3 id="etape-2-utiliser-la-balise-private" tabindex="-1">Étape 2 : Utiliser la balise <code>&lt;private&gt;</code> <a class="header-anchor" href="#etape-2-utiliser-la-balise-private" aria-label="Permalink to &quot;Étape 2 : Utiliser la balise `&lt;private&gt;`&quot;">​</a></h3><p>Lorsque vous demandez à l&#39;Agent de se souvenir de contenu contenant des informations sensibles en langage naturel pendant la conversation, vous pouvez envelopper les parties sensibles avec la balise <code>&lt;private&gt;</code>.</p><p><strong>Démonstration de l&#39;action</strong> :</p><p>Dites à l&#39;Agent :</p><blockquote><p>Souviens-toi, l&#39;adresse IP de la base de données de production est 192.168.1.10, mais le mot de passe root est <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>, ne divulgue pas le mot de passe.</p></blockquote><p><strong>Ce que vous devriez voir</strong> : L&#39;Agent appelle l&#39;outil <code>supermemory</code> pour sauvegarder la mémoire. Bien que la réponse de l&#39;Agent puisse contenir le mot de passe (car il est dans le contexte), <strong>la mémoire réellement sauvegardée dans le cloud Supermemory</strong> a été masquée.</p><h3 id="etape-3-verifier-le-resultat-du-masquage" tabindex="-1">Étape 3 : Vérifier le résultat du masquage <a class="header-anchor" href="#etape-3-verifier-le-resultat-du-masquage" aria-label="Permalink to &quot;Étape 3 : Vérifier le résultat du masquage&quot;">​</a></h3><p>Nous pouvons vérifier par une recherche si le mot de passe a vraiment été stocké.</p><p><strong>Action</strong> : Demandez à l&#39;Agent de rechercher la mémoire précédente :</p><blockquote><p>Recherche le mot de passe de la base de données de production.</p></blockquote><p><strong>Résultat attendu</strong> : Le contenu que l&#39;Agent récupère de Supermemory devrait être : <code>L&#39;adresse IP de la base de données de production est 192.168.1.10, mais le mot de passe root est [REDACTED]...</code></p><p>Si l&#39;Agent vous dit &quot;le mot de passe est [REDACTED]&quot;, cela signifie que le mécanisme de masquage fonctionne correctement.</p><h2 id="idees-fausses-courantes" tabindex="-1">Idées fausses courantes <a class="header-anchor" href="#idees-fausses-courantes" aria-label="Permalink to &quot;Idées fausses courantes&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Idée fausse 1 : Tout le code sera téléchargé</p><p><strong>Fait</strong> : Le plugin <strong>ne</strong> téléchargera pas automatiquement votre dépôt de code entier. Il ne téléchargera que des segments spécifiques lors de l&#39;exécution de <code>/supermemory-init</code> pour l&#39;analyse initiale, ou lorsque l&#39;Agent décide explicitement de &quot;se souvenir&quot; d&#39;une logique de code spécifique.</p></div><div class="warning custom-block"><p class="custom-block-title">Idée fausse 2 : Les fichiers .env seront automatiquement chargés</p><p><strong>Fait</strong> : Le plugin lit <code>SUPERMEMORY_API_KEY</code> dans l&#39;environnement du processus. Si vous placez un fichier <code>.env</code> dans le répertoire racine du projet, le plugin <strong>ne</strong> le lira pas automatiquement, sauf si votre terminal ou le programme principal OpenCode l&#39;a chargé.</p></div><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir les emplacements du code source</strong></summary><blockquote><p>Date de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Logique de masquage de confidentialité</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>Chargement de la clé API</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>Appel au masquage par le plugin</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>Fonctions clés</strong> :</p><ul><li><code>stripPrivateContent(content)</code> : Exécute le remplacement regex, transformant le contenu <code>&lt;private&gt;</code> en <code>[REDACTED]</code>.</li><li><code>loadConfig()</code> : Charge le fichier de configuration local, priorité supérieure aux variables d&#39;environnement.</li></ul></details><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Félicitations ! Vous avez terminé les cours principaux d&#39;opencode-supermemory !</p><p>Ensuite, vous pouvez :</p><ul><li>Revoir la <a href="/docs/opencodedocs/fr/supermemoryai/opencode-supermemory/advanced/configuration/">configuration avancée</a> pour plus d&#39;options de personnalisation.</li></ul></blockquote>',35)])])}const g=t(s,[["render",a]]);export{m as __pageData,g as default};
